import Vue from 'vue';
import Router from 'vue-router';

Vue.use(Router);

export default new Router({
    routes: [
        {
            path: '/',
            name: 'home',
            component: () => import('../views/Home.vue')
        },
        {
            path: '/blog',
            name: 'blog',
            component: () => import('../views/Blog.vue')
        },
        {
            path: '/detail/:id',
            name: 'detail',
            component: () => import('../views/Detail.vue')
        },
        {
            path: '/about',
            name: 'about',
            component: () => import('../views/About.vue')
        }
    ]
})
